import{_ as i,o as n,c as a,ag as e}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"[Client / App Specs] Sprint 3: Khám phá & Tìm kiếm (Discovery UX)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/02-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/06-client-app-specs.md","filePath":"99-tham-khao/archive/02-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/06-client-app-specs.md"}'),o={name:"99-tham-khao/archive/02-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/06-client-app-specs.md"};function r(h,t,l,c,s,p){return n(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="client-app-specs-sprint-3-kham-pha-tim-kiem-discovery-ux" tabindex="-1">[Client / App Specs] Sprint 3: Khám phá &amp; Tìm kiếm (Discovery UX) <a class="header-anchor" href="#client-app-specs-sprint-3-kham-pha-tim-kiem-discovery-ux" aria-label="Permalink to &quot;[Client / App Specs] Sprint 3: Khám phá &amp; Tìm kiếm (Discovery UX)&quot;">​</a></h1><p>Đặc tả chi tiết giao diện và hiển thị các công cụ Tìm kiếm, Bộ lọc dành cho Khách hàng.</p><h2 id="_1-thanh-tim-kiem-đa-nang-omni-search-ux" tabindex="-1">1. Thanh Tìm kiếm Đa năng (Omni-Search UX) <a class="header-anchor" href="#_1-thanh-tim-kiem-đa-nang-omni-search-ux" aria-label="Permalink to &quot;1. Thanh Tìm kiếm Đa năng (Omni-Search UX)&quot;">​</a></h2><ul><li><strong>Web Client</strong>: <ul><li><strong>UI</strong>: Thanh search trung tâm tại Homepage (hero section).</li><li><strong>Interaction</strong>: Khi click vào ô input -&gt; Pop-over hiển thị &quot;Từ khóa xu hướng&quot; (Hot keywords). Khi nhập 1+ ký tự -&gt; Autocomplete xổ xuống danh sách Tour/Điểm đến.</li></ul></li><li><strong>Mobile App</strong>: <ul><li><strong>UI</strong>: Icon Search tại góc phải thanh Header hoặc Tab Discovery riêng biệt.</li><li><strong>Interaction</strong>: Bàn phím tự động hiển thị nút &quot;Tìm&quot; (Search action).</li></ul></li></ul><h2 id="_2-bo-loc-thong-minh-smart-filter-specs" tabindex="-1">2. Bộ lọc Thông minh (Smart Filter Specs) <a class="header-anchor" href="#_2-bo-loc-thong-minh-smart-filter-specs" aria-label="Permalink to &quot;2. Bộ lọc Thông minh (Smart Filter Specs)&quot;">​</a></h2><ul><li><strong>Web Client (Sidebar)</strong>: <ul><li><strong>Price</strong>: Thanh trượt (Range Slider) từ 0 VNĐ - 100.000.000 VNĐ.</li><li><strong>Stars</strong>: Danh sách checkbox: [x] 5 sao, [ ] 4 sao, [ ] 3 sao.</li><li><strong>Region</strong>: Tabs hoặc Radio buttons: [Tất cả] [Miền Bắc] [Miền Trung] [Miền Nam].</li></ul></li><li><strong>Mobile App (Floating Sheet)</strong>: <ul><li><strong>UI</strong>: Nút &quot;Lọc&quot; (FAB) hiển thị số lượng bộ lọc đang áp dụng (e.g. &quot;Lọc (2)&quot;).</li><li><strong>Sheet Content</strong>: Các accordion thu gọn cho từng nhóm lọc.</li></ul></li></ul><h2 id="_3-man-hinh-ket-qua-search-result-grid" tabindex="-1">3. Màn hình Kết quả (Search Result Grid) <a class="header-anchor" href="#_3-man-hinh-ket-qua-search-result-grid" aria-label="Permalink to &quot;3. Màn hình Kết quả (Search Result Grid)&quot;">​</a></h2><ul><li><strong>Layout</strong>: Grid 3-4 cột (Web), 1-2 cột (App).</li><li><strong>Sorting Options</strong>: Mới nhất, Giá thấp -&gt; cao, Giá cao -&gt; thấp, Đánh giá tốt nhất.</li><li><strong>Micro-interaction</strong>: Hiệu ứng Hover card (Web) và Hiệu ứng Scale nhấn (App).</li></ul><h2 id="_4-đac-ta-ban-đo-map-view-ui" tabindex="-1">4. Đặc tả Bản đồ (Map View UI) <a class="header-anchor" href="#_4-đac-ta-ban-đo-map-view-ui" aria-label="Permalink to &quot;4. Đặc tả Bản đồ (Map View UI)&quot;">​</a></h2><ul><li><strong>Component</strong>: <code>Google Maps</code> / <code>Leaflet</code>.</li><li><strong>UI</strong>: Các Pin (Marker) hiển thị giá tiền của tour (e.g. 1.2M).</li><li><strong>Interaction</strong>: Khi click vào Pin -&gt; Info window nhỏ hiển thị ảnh &amp; tên tour -&gt; Click trỏ vào Detail.</li></ul><hr><p><em>Tài liệu đặc tả Client/App cho Sprint 3.</em></p>',12)])])}const u=i(o,[["render",r]]);export{m as __pageData,u as default};
